// ═══════════════════════════════════════════════════════════════════
// GOBSTOPPERS - 3D Spring-Node Physics System
// Synthograsizer Workflow Template
// ═══════════════════════════════════════════════════════════════════

const CW = 500;

// ─── PALETTES (RGB arrays) ────────────────────────────────────────
const PALETTES = {
  'primary':      [[255,0,0],[0,255,0],[0,0,255],[255,255,0],[255,0,255]],
  'ocean':        [[0,105,148],[0,160,199],[0,191,243],[72,215,255],[143,244,255]],
  'sunset':       [[255,94,77],[255,153,31],[255,212,59],[245,233,129],[74,144,226]],
  'forest':       [[0,128,43],[44,176,55],[60,179,113],[121,222,135],[169,240,166]],
  'candy':        [[255,158,253],[255,102,255],[255,50,233],[255,20,147],[199,0,57]],
  'retro':        [[255,61,127],[255,112,67],[255,209,0],[0,204,204],[0,51,102]],
  'pastel goth':  [[95,61,255],[203,49,222],[255,21,182],[255,105,80],[255,245,105]],
  'harvest moon': [[243,188,63],[239,139,61],[225,97,61],[196,54,70],[119,46,73]]
};

// ─── PARAMETER MAPS ───────────────────────────────────────────────
const countMap = { few:3, some:6, moderate:10, many:16, cluster:25, swarm:40 };
const sizeMap = { tiny:12, small:24, medium:48, large:72, massive:96, colossal:128 };
const lengthMap = { tight:40, close:100, medium:200, spread:320, wide:420, vast:512 };
const stiffMap = { rigid:-0.009, firm:-0.007, moderate:-0.005, elastic:-0.003, loose:-0.001, floating:-0.0005 };
const weightMap = { invisible:0, hairline:0.5, thin:2, medium:4, thick:6, heavy:10 };
const rotMap = { still:0, slow:0.5, moderate:1.5, fast:3, rapid:6, frantic:10 };
const meshMap = { invisible:0, light:1, medium:3, bold:6, heavy:9 };

// ─── STATE ────────────────────────────────────────────────────────
let nodes = [];
let springs = [];
let palette = [];
let prevCount = -1;
let prevPalName = '';
let prevLength = -1;
let prevStiff = 0;

// ─── HELPERS ──────────────────────────────────────────────────────
function palColor(pal) {
  let c = pal[Math.floor(p.random(pal.length))];
  return p.color(c[0], c[1], c[2]);
}

function initSystem(count, pal, restLen, stiff) {
  nodes = [];
  springs = [];
  palette = pal;
  for (let i = 0; i < count; i++) {
    nodes.push({
      pos: p.createVector(p.random(-200,200), p.random(-200,200), p.random(-200,200)),
      vel: p.createVector(0,0,0),
      acc: p.createVector(0,0,0),
      color1: palColor(pal),
      color2: palColor(pal),
      rotX: p.random(0, p.TWO_PI),
      rotY: p.random(0, p.TWO_PI),
      rotZ: p.random(0, p.TWO_PI)
    });
  }
  for (let i = 0; i < nodes.length - 1; i++) {
    springs.push({
      nodeA: nodes[i],
      nodeB: nodes[i+1],
      length: restLen,
      stiffness: stiff,
      color1: palColor(pal),
      color2: palColor(pal)
    });
  }
}

function recolorSystem(pal) {
  palette = pal;
  for (let n of nodes) {
    n.color1 = palColor(pal);
    n.color2 = palColor(pal);
  }
  for (let s of springs) {
    s.color1 = palColor(pal);
    s.color2 = palColor(pal);
  }
}

// ─── SETUP ────────────────────────────────────────────────────────
p.setup = function() {
  p.createCanvas(CW, CW, p.WEBGL);
  p.print('Gobstoppers ready');
};

// ─── DRAW ─────────────────────────────────────────────────────────
p.draw = function() {
  // Read variables
  let vCount     = p.getSynthVar('node_count') || 'moderate';
  let vSize      = p.getSynthVar('node_size') || 'medium';
  let vShape     = p.getSynthVar('node_shape') || 'sphere';
  let vLength    = p.getSynthVar('spring_length') || 'medium';
  let vStiff     = p.getSynthVar('spring_stiffness') || 'moderate';
  let vWeight    = p.getSynthVar('spring_weight') || 'medium';
  let vSpType    = p.getSynthVar('spring_type') || 'linear';
  let vRot       = p.getSynthVar('rotation_speed') || 'moderate';
  let vRender    = p.getSynthVar('render_mode') || 'nodes and springs';
  let vTrail     = p.getSynthVar('trail_mode') || 'off';
  let vPalette   = p.getSynthVar('color_palette') || 'primary';
  let vTransition= p.getSynthVar('color_transition') || 'off';
  let vMesh      = p.getSynthVar('mesh_weight') || 'invisible';

  // Map to numeric
  let numNodes   = countMap[vCount] || 10;
  let nodeSize   = sizeMap[vSize] || 48;
  let restLen    = lengthMap[vLength] || 200;
  let stiff      = stiffMap[vStiff] || -0.005;
  let springWt   = weightMap[vWeight] || 4;
  let rotSpeed   = rotMap[vRot] || 1.5;
  let meshWt     = meshMap[vMesh] || 0;
  let pal        = PALETTES[vPalette] || PALETTES['primary'];
  let trailOn    = vTrail === 'on';
  let transOn    = vTransition === 'on';
  let showNodes  = vRender === 'nodes and springs' || vRender === 'nodes only';
  let showSprings= vRender === 'nodes and springs' || vRender === 'springs only';

  // Reinit on changes
  if (numNodes !== prevCount || vPalette !== prevPalName) {
    prevCount = numNodes;
    prevPalName = vPalette;
    prevLength = restLen;
    prevStiff = stiff;
    initSystem(numNodes, pal, restLen, stiff);
  }
  // Update spring params if changed
  if (restLen !== prevLength || stiff !== prevStiff) {
    prevLength = restLen;
    prevStiff = stiff;
    for (let s of springs) {
      s.length = restLen;
      s.stiffness = stiff;
    }
  }

  // Background
  if (trailOn) {
    // Semi-transparent overlay for trail effect
    p.push();
    p.noStroke();
    p.fill(0, 0, 0, 25);
    p.translate(0, 0, -1);
    p.plane(CW * 2, CW * 2);
    p.pop();
  } else {
    p.background(0);
  }

  // Lighting for 3D
  p.ambientLight(80);
  p.directionalLight(200, 200, 200, 0.5, 0.5, -1);
  p.directionalLight(100, 100, 150, -0.5, -0.3, -0.8);

  // Color transition factor
  let tFactor = transOn ? (Math.sin(p.millis() * 0.001) + 1) * 0.5 : 0;

  // Update springs (physics)
  for (let s of springs) {
    let force = p5.Vector.sub(s.nodeA.pos, s.nodeB.pos);
    let distance = force.mag();
    force.normalize();
    force.mult(distance - s.length);
    if (vSpType === 'reverse') {
      force.mult(-s.stiffness);
    } else if (vSpType === 'damped') {
      force.mult(s.stiffness * 0.85);
    } else if (vSpType === 'hookean') {
      force.mult(s.stiffness * 1.2);
    } else {
      force.mult(s.stiffness);
    }
    s.nodeA.acc.add(force);
    let neg = force.copy().mult(-1);
    s.nodeB.acc.add(neg);
  }

  // Update nodes (physics + rotation)
  for (let n of nodes) {
    n.vel.add(n.acc);
    n.vel.mult(0.98); // damping
    n.pos.add(n.vel);
    n.acc.mult(0);
    n.rotX += p.radians(rotSpeed);
    n.rotY += p.radians(rotSpeed);
    n.rotZ += p.radians(rotSpeed * 0.7);
  }

  // Draw springs
  if (showSprings && springWt > 0) {
    for (let s of springs) {
      p.strokeWeight(springWt);
      let col;
      if (transOn) {
        col = p.lerpColor(s.color1, s.color2, tFactor);
      } else {
        col = s.color1;
      }
      p.stroke(col);
      p.line(s.nodeA.pos.x, s.nodeA.pos.y, s.nodeA.pos.z,
             s.nodeB.pos.x, s.nodeB.pos.y, s.nodeB.pos.z);
    }
  }

  // Draw nodes
  if (showNodes) {
    for (let n of nodes) {
      p.push();
      let col;
      if (transOn) {
        col = p.lerpColor(n.color1, n.color2, tFactor);
      } else {
        col = n.color1;
      }
      p.fill(col);
      if (meshWt > 0) {
        p.stroke(0);
        p.strokeWeight(meshWt);
      } else {
        p.noStroke();
      }
      p.translate(n.pos.x, n.pos.y, n.pos.z);
      p.rotateX(n.rotX);
      p.rotateY(n.rotY);
      p.rotateZ(n.rotZ);

      switch(vShape) {
        case 'box':
          p.box(nodeSize); break;
        case 'cone':
          p.cone(nodeSize, nodeSize * 2); break;
        case 'cylinder':
          p.cylinder(nodeSize, nodeSize * 2); break;
        case 'torus':
          p.torus(nodeSize, nodeSize / 2); break;
        case 'icosahedron':
          p.sphere(nodeSize, 4, 3); break;
        default:
          p.sphere(nodeSize); break;
      }
      p.pop();
    }
  }
};
